#!/usr/bin/env python3
"""One-shot: fill all missing ES and FR keys in marketing.json."""
import json
from pathlib import Path

TRANSLATIONS = Path(__file__).resolve().parent.parent / "translations"

def load(locale, scope):
    p = TRANSLATIONS / locale / f"{scope}.json"
    with open(p, encoding="utf-8") as f:
        return json.load(f)

def save(data, locale, scope):
    p = TRANSLATIONS / locale / f"{scope}.json"
    with open(p, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent="\t")
        f.write("\n")

def set_nested(obj, key, value):
    parts = key.split(".")
    cur = obj
    for part in parts[:-1]:
        if part not in cur or not isinstance(cur[part], dict):
            cur[part] = {}
        cur = cur[part]
    cur[parts[-1]] = value

