def apply():
    es_data = load("es", "marketing")
    fr_data = load("fr", "marketing")
    count = 0
    for key, (es_val, fr_val) in MISSING.items():
        set_nested(es_data, key, es_val)
        set_nested(fr_data, key, fr_val)
        count += 1
    save(es_data, "es", "marketing")
    save(fr_data, "fr", "marketing")
    print(f"✓ Applied {count} keys to es/marketing.json and fr/marketing.json")

if __name__ == "__main__":
    apply()
